import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { useWishlist } from '../context/WishlistContext';
import { faHouse } from '@fortawesome/free-regular-svg-icons';
import './BottomBar.css';

const faStore = {
  prefix: 'far',
  iconName: 'store',
  icon: [
    16, 16,
    [],
    "",
    "M2.97 1.35A1 1 0 0 1 3.73 1h8.54a1 1 0 0 1 .76.35l2.609 3.044A1.5 1.5 0 0 1 16 5.37v.255a2.375 2.375 0 0 1-4.25 1.458A2.37 2.37 0 0 1 9.875 8 2.37 2.37 0 0 1 8 7.083 2.37 2.37 0 0 1 6.125 8a2.37 2.37 0 0 1-1.875-.917A2.375 2.375 0 0 1 0 5.625V5.37a1.5 1.5 0 0 1 .361-.976zm1.78 4.275a1.375 1.375 0 0 0 2.75 0 .5.5 0 0 1 1 0 1.375 1.375 0 0 0 2.75 0 .5.5 0 0 1 1 0 1.375 1.375 0 1 0 2.75 0V5.37a.5.5 0 0 0-.12-.325L12.27 2H3.73L1.12 5.045A.5.5 0 0 0 1 5.37v.255a1.375 1.375 0 0 0 2.75 0 .5.5 0 0 1 1 0M1.5 8.5A.5.5 0 0 1 2 9v6h1v-5a1 1 0 0 1 1-1h3a1 1 0 0 1 1 1v5h6V9a.5.5 0 0 1 1 0v6h.5a.5.5 0 0 1 0 1H.5a.5.5 0 0 1 0-1H1V9a.5.5 0 0 1 .5-.5M4 15h3v-5H4zm5-5a1 1 0 0 1 1-1h2a1 1 0 0 1 1 1v3a1 1 0 0 1-1 1h-2a1 1 0 0 1-1-1zm3 0h-2v3h2z"
  ]
};

const faBagShopping = {
  prefix: 'far',
  iconName: 'bag-shopping',
  icon: [
    16, 16,
    [],
    "",
    "M8 1a2.5 2.5 0 0 1 2.5 2.5V4h-5v-.5A2.5 2.5 0 0 1 8 1m3.5 3v-.5a3.5 3.5 0 1 0-7 0V4H1v10a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2V4zM2 5h12v9a1 1 0 0 1-1 1H3a1 1 0 0 1-1-1z"
  ]
};

export default function BottomBar() {
  const location = useLocation();
  const { totalItems } = useWishlist();

  const isActive = (path) => location.pathname === path;

  return (
    <div className="bottom-nav">
      <Link to="/" className={`bottom-nav__item ${isActive('/') ? 'bottom-nav__item--active' : ''}`}>
        <FontAwesomeIcon icon={faHouse} />
        <span>Home</span>
      </Link>
      <Link to="/shop" className={`bottom-nav__item ${isActive('/shop') ? 'bottom-nav__item--active' : ''}`}>
        <FontAwesomeIcon icon={faStore} />
        <span>Shop</span>
      </Link>
      <Link to="/wishlist" className={`bottom-nav__item ${isActive('/wishlist') ? 'bottom-nav__item--active' : ''}`}>
        <div className="bottom-nav__icon-wrap">
          <FontAwesomeIcon icon={faBagShopping} />
          {totalItems > 0 && <span className="bottom-nav__badge">{totalItems}</span>}
        </div>
        <span>Orders</span>
      </Link>
    </div>
  );
}
